		cin>>s;
		s=' '+s;
		for(int i=1;i<=n;i++)
		{
			a[i]=s[i]-'0'; 
		}
		l=1;r=n;ans=n;
		while(l<=r)
		{
			if(a[l]!=a[r]) ans-=2,l++,r--;
